import java.util.Scanner;

public class BufferOverflowExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string (max 10 characters): ");
        String input = scanner.nextLine();

        // Limit the input size to 10 characters
        if (input.length() > 10) {
            System.out.println("Input exceeds maximum length of 10 characters. Truncating...");
            input = input.substring(0, 10);
        }

        char[] buffer = new char[10];
        input.getChars(0, input.length(), buffer, 0); // Copy user input to buffer

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
